func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testGet(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.GetTrainingPipelineRequest{
			Name: "",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument if the provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.GetTrainingPipelineRequest{
			Name: "invalid resource name",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Resource should be returned without errors if it exists.
	t.Run("exists", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		getResp, err := fx.Service().GetTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.GetTrainingPipelineRequest{
			Name: created.Name,
		}))
		msg := getResp.Msg
		assert.NilError(t, err)
		assert.DeepEqual(t, msg, created, protocmp.Transform())
	})

	// Method should fail with NotFound if the resource does not exist.
	t.Run("not found", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.GetTrainingPipelineRequest{
			Name: created.Name + "notfound",
		}))
		assert.Equal(t, connect.CodeNotFound, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument if the provided name only contains wildcards ('-')
	t.Run("only wildcards", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.GetTrainingPipelineRequest{
			Name: "projects/-/locations/-/trainingPipelines/-",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
			Parent: "invalid resource name",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
			Parent:    parent,
			PageToken: "invalid page token",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
			Parent:   parent,
			PageSize: -10,
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	{
		const resourcesCount = 15
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.TrainingPipeline, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
				Parent:   parent,
				PageSize: 999,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.TrainingPipelines,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TrainingPipeline) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
				Parent:   parent,
				PageSize: resourcesCount,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Equal(t, "", response.NextPageToken)
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
				Parent:   parent,
				PageSize: resourcesCount - 1,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Check(t, response.NextPageToken != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.TrainingPipeline, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
					Parent:    parent,
					PageSize:  1,
					PageToken: nextPageToken,
				}))
				response := listResp.Msg
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.TrainingPipelines))
				msgs = append(msgs, response.TrainingPipelines...)
				nextPageToken = response.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TrainingPipeline) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// Method should not return deleted resources.
		t.Run("deleted", func(t *testing.T) {
			fx.maybeSkip(t)
			const deleteCount = 5
			for i := 0; i < deleteCount; i++ {
				_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
					Name: parentMsgs[i].Name,
				}))
				assert.NilError(t, err)
			}
			listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
				Parent:   parent,
				PageSize: 9999,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs[deleteCount:],
				response.TrainingPipelines,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TrainingPipeline) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
	{
		const resourcesCount = 101
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.TrainingPipeline, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// Listing resource with page size zero should eventually return all resources.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.TrainingPipeline, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListTrainingPipelines(fx.Context(), connect.NewRequest(&aiplatformpb.ListTrainingPipelinesRequest{
					Parent:    parent,
					PageSize:  0,
					PageToken: nextPageToken,
				}))
				page := listResp.Msg
				assert.NilError(t, err)
				msgs = append(msgs, page.TrainingPipelines...)
				nextPageToken = page.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TrainingPipeline) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testDelete(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: "",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument if the provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: "invalid resource name",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Resource should be deleted without errors if it exists.
	t.Run("exists", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: created.Name,
		}))
		assert.NilError(t, err)
	})

	// Method should fail with NotFound if the resource does not exist.
	t.Run("not found", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: created.Name + "notfound",
		}))
		assert.Equal(t, connect.CodeNotFound, connect.CodeOf(err), err)
	})

	// Method should fail with NotFound if the resource was already deleted. This also applies to soft-deletion.
	t.Run("already deleted", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		deleteResp, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: created.Name,
		}))
		deleted := deleteResp.Msg
		assert.NilError(t, err)
		_ = deleted
		_, err = fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: created.Name,
		}))
		assert.Equal(t, connect.CodeNotFound, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument if the provided name only contains wildcards ('-')
	t.Run("only wildcards", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTrainingPipelineRequest{
			Name: "projects/-/locations/-/trainingPipelines/-",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) nextParent(t *testing.T, pristine bool) string {
	if pristine {
		fx.currParent++
	}
	if fx.currParent >= len(fx.Parents) {
		t.Fatal("need at least", fx.currParent+1, "parents")
	}
	return fx.Parents[fx.currParent]
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) peekNextParent(t *testing.T) string {
	next := fx.currParent + 1
	if next >= len(fx.Parents) {
		t.Fatal("need at least", next+1, "parents")
	}
	return fx.Parents[next]
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) maybeSkip(t *testing.T) {
	for _, skip := range fx.Skip {
		if strings.Contains(t.Name(), skip) {
			t.Skip("skipped because of .Skip")
		}
	}
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) create(t *testing.T, parent string) *aiplatformpb.TrainingPipeline {
	t.Helper()
	createResp, err := fx.Service().CreateTrainingPipeline(fx.Context(), connect.NewRequest(&aiplatformpb.CreateTrainingPipelineRequest{
		Parent:           parent,
		TrainingPipeline: fx.Create(parent),
	}))
	created := createResp.Msg
	assert.NilError(t, err)
	return created
}
